#include <stdio.h>
#include <stdlib.h>

int possible(long long k, long long target) {
    return llabs(target) <= k && ((k - target) & 1LL) == 0;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long P,Q; scanf("%d %lld %lld", &N, &P, &Q);
        char *S = (char*)malloc(N+5);
        scanf("%s", S);
        long long cntEven = 0; // number of positions with even zero count
        int zeroParity = 0; // 0 = even, 1 = odd
        for(int i=0;i<N;i++){
            if(S[i]=='0') zeroParity ^= 1;
            if(zeroParity==0) cntEven++;
        }
        long long cntOdd = N - cntEven;
        int ok = 0;
        // initial axis = x
        long long kx = cntEven, ky = cntOdd;
        if(possible(kx, P) && possible(ky, Q)) ok = 1;
        // initial axis = y
        kx = cntOdd; ky = cntEven;
        if(possible(kx, P) && possible(ky, Q)) ok = 1;
        printf(ok?"YES\n":"NO\n");
        free(S);
    }
    return 0;
}

