#include <bits/stdc++.h>
using namespace std;

bool possible(long long k, long long target){
    return llabs(target) <= k && ((k - target) & 1LL) == 0;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; long long P,Q; cin>>N>>P>>Q;
        string S; cin>>S;
        long long cntEven=0; int parity=0; // parity of zero count
        for(char c: S){
            if(c=='0') parity ^= 1;
            if(parity==0) ++cntEven;
        }
        long long cntOdd = N - cntEven;
        bool ok = false;
        // start with x
        long long kx = cntEven, ky = cntOdd;
        if(possible(kx,P) && possible(ky,Q)) ok = true;
        // start with y
        kx = cntOdd; ky = cntEven;
        if(possible(kx,P) && possible(ky,Q)) ok = true;
        cout << (ok?"YES":"NO") << '\n';
    }
    return 0;
}

