import java.io.*;
import java.util.*;

public class Main {
    static boolean possible(long k, long target){
        return Math.abs(target) <= k && ((k - target) & 1L) == 0L;
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while(T-- > 0){
            int N = fs.nextInt();
            long P = fs.nextLong();
            long Q = fs.nextLong();
            String S = fs.next();
            long cntEven = 0;
            int parity = 0; // 0 = even zeros so far
            for(int i=0;i<N;i++){
                if(S.charAt(i)=='0') parity ^= 1;
                if(parity==0) cntEven++;
            }
            long cntOdd = N - cntEven;
            boolean ok = false;
            long kx = cntEven, ky = cntOdd; // start with x
            if(possible(kx,P) && possible(ky,Q)) ok = true;
            kx = cntOdd; ky = cntEven; // start with y
            if(possible(kx,P) && possible(ky,Q)) ok = true;
            sb.append(ok?"YES":"NO").append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for Java
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if(ptr >= len){
                len = in.read(buffer);
                ptr = 0;
                if(len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        private boolean isSpace(int c){ return c==' '||c=='\n'||c=='\r'||c=='\t'||c==-1; }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while(isSpace(c = readByte()));
            do{ sb.append((char)c); } while(!isSpace(c = readByte()));
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        long nextLong() throws IOException { return Long.parseLong(next()); }
    }
}

