function possible(k, target){
  return Math.abs(target) <= k && ((k - target) & 1) === 0;
}
for(let t=0; t<T; t++){
  const N = Number(input[idx++]);
  const P = Number(input[idx++]);
  const Q = Number(input[idx++]);
  const S = input[idx++];
  let cntEven = 0;
  let parity = 0; // parity of zeros seen so far
  for(let i=0;i<N;i++){
    if(S[i] === '0') parity ^= 1;
    if(parity === 0) cntEven++;
  }
  const cntOdd = N - cntEven;
  let ok = false;
  // start with x
  let kx = cntEven, ky = cntOdd;
  if(possible(kx, P) && possible(ky, Q)) ok = true;
  // start with y
